function maxDepth(s) {
    let depth = 0, maxDepth = 0;

    for (const c of s) {
        if (c === '(') {
            depth++;
            maxDepth = Math.max(depth, maxDepth);
        } else if (c === ')') {
            depth--;
        }
    }

    return maxDepth;
}
