public int maxDepth(String s) {
    int depth = 0, maxDepth = 0;

    for (char c : s.toCharArray()) {
        if (c == '(') {
            depth++;
            maxDepth = Math.max(depth, maxDepth);
        } else if (c == ')') {
            depth--;
        }
    }

    return maxDepth;
}
